import './Banner.scss';

import { useDeviceSize } from ':helpers';
import { classNames } from ':helpers/classnames';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React, { forwardRef } from 'react';

import { Icon } from '../Icon';
import { IconButton } from '../IconButton';
import type { BannerProps } from './Banner.types';
import { ButtonContainer } from './ButtonContainer';

export const Banner = forwardRef<HTMLDivElement, BannerProps>(
	({ title, type = 'horizontal', color = 'info', actions, onClose, iconName, className }, ref) => {
		const { isExtraSmallDevice } = useDeviceSize();
		const _type = isExtraSmallDevice ? 'vertical' : type;
		if (type === 'horizontal' && isExtraSmallDevice) {
			console.warn('[dsb-banner] Для мобильного баннер доступен только type = vertical');
		}
		return (
			<div
				role="banner"
				data-testid="Banner"
				ref={ref}
				className={classNames(
					'banner banner-container',
					`banner__type-${_type}`,
					`banner__color-${color}`,
					!!onClose && 'banner__close-button',
					className,
				)}
			>
				<div className="banner-title">
					<div className="banner-title-text">
						{iconName && <Icon size="medium" iconName={iconName} className="banner-title-icon" />}
						{title}
					</div>
				</div>
				{actions && <ButtonContainer actions={actions} className="banner-actions" />}
				{onClose && (
					<IconButton
						size="large"
						className="icon-button-close icon-close"
						onClick={onClose}
						iconName={Icons.Close}
						aria-label="Закрыть баннер"
					/>
				)}
			</div>
		);
	},
);
